params.script:
// Script Template: condition_group
// 入力モジュールの出力値をグループ番号に分類（多段分岐用）
// プレースホルダー: OpenAI_診療科 = 入力元モジュール名（OpenAI モジュール）
// プレースホルダー: {"骨粗しょう症検診": "1", "子宮がん検診": "1", "乳がん検診": "1", "産婦人科": "1", "一般内科": "1", "特定健診": "1", "予防接種": "1", "健診希望": "1"} = 値→グループ番号の JSON オブジェクト
// プレースホルダー: 2 = マッピングに該当しない場合のデフォルトグループ番号
// 出力: グループ番号文字列（"1", "2", ... "10"）

var input = $runner.getModuleResult("OpenAI_診療科");
var mapping = {"骨粗しょう症検診": "1", "子宮がん検診": "1", "乳がん検診": "1", "産婦人科": "1", "一般内科": "1", "特定健診": "1", "予防接種": "1", "健診希望": "1"};
var group = mapping[input];
if (!group) { group = "2"; }
$runner.setResult(group);
